DROP TABLE IF EXISTS PERSON_INFO_NOTE_mcv;

-- Create MCV table for PERSON_INFO.NOTE, with a unique mcv_id
CREATE TABLE PERSON_INFO_NOTE_mcv AS
WITH base AS (
    SELECT NOTE, COUNT(*) AS freq
    FROM PERSON_INFO
    WHERE NOTE IS NOT NULL
    GROUP BY NOTE
    ORDER BY freq DESC
    LIMIT 5000
)
SELECT
    ROW_NUMBER() OVER (ORDER BY freq DESC) AS mcv_id,
    NOTE,
    freq
FROM base;

DROP TABLE IF EXISTS ROLE_TYPE_ROLE_mcv;

-- Create MCV table for ROLE_TYPE.ROLE, with a unique mcv_id
CREATE TABLE ROLE_TYPE_ROLE_mcv AS
WITH base AS (
    SELECT ROLE, COUNT(*) AS freq
    FROM ROLE_TYPE
    WHERE ROLE IS NOT NULL
    GROUP BY ROLE
    ORDER BY freq DESC
    LIMIT 5000
)
SELECT
    ROW_NUMBER() OVER (ORDER BY freq DESC) AS mcv_id,
    ROLE,
    freq
FROM base;

DROP TABLE IF EXISTS TITLE_PRODUCTION_YEAR_mcv;

-- Create MCV table for TITLE.PRODUCTION_YEAR, with a unique mcv_id
CREATE TABLE TITLE_PRODUCTION_YEAR_mcv AS
WITH base AS (
    SELECT PRODUCTION_YEAR, COUNT(*) AS freq
    FROM TITLE
    WHERE PRODUCTION_YEAR IS NOT NULL
    GROUP BY PRODUCTION_YEAR
    ORDER BY freq DESC
    LIMIT 5000
)
SELECT
    ROW_NUMBER() OVER (ORDER BY freq DESC) AS mcv_id,
    PRODUCTION_YEAR,
    freq
FROM base;

DROP TABLE IF EXISTS TITLE_TITLE_mcv;

-- Create MCV table for TITLE.TITLE, with a unique mcv_id
CREATE TABLE TITLE_TITLE_mcv AS
WITH base AS (
    SELECT TITLE, COUNT(*) AS freq
    FROM TITLE
    WHERE TITLE IS NOT NULL
    GROUP BY TITLE
    ORDER BY freq DESC
    LIMIT 5000
)
SELECT
    ROW_NUMBER() OVER (ORDER BY freq DESC) AS mcv_id,
    TITLE,
    freq
FROM base;

DROP TABLE IF EXISTS TITLE_EPISODE_NR_histogram;
CREATE TABLE TITLE_EPISODE_NR_histogram (
    bucket_id   INT NOT NULL,
    layer       INT NOT NULL,
    lower_bound INT,
    upper_bound INT,
    bucket_type TEXT
