CREATE TEMP TABLE Degree_AKA_NAME_PERSON_ID AS
SELECT
    AKA_NAME.PERSON_ID AS PERSON_ID,
    COUNT(*) AS deg
FROM AKA_NAME

WHERE AKA_NAME.PERSON_ID IS NOT NULL
GROUP BY
    AKA_NAME.PERSON_ID
HAVING COUNT(*) > 0
ORDER BY deg DESC
;

