DROP TABLE IF EXISTS Degree_AKA_NAME_NAME_PERSON_ID;

-- Create aggregator table Degree_AKA_NAME_NAME_PERSON_ID for MCV AKA_NAME.NAME -- MCV
CREATE TEMP TABLE Degree_AKA_NAME_NAME_PERSON_ID AS
SELECT
    mcvt.mcv_id AS mcv_id,
    AKA_NAME.PERSON_ID AS PERSON_ID,
    COUNT(*) AS deg
FROM AKA_NAME
JOIN AKA_NAME_NAME_mcv mcvt ON AKA_NAME.NAME = mcvt.NAME
WHERE AKA_NAME.PERSON_ID IS NOT NULL
GROUP BY
    mcvt.mcv_id, AKA_NAME.PERSON_ID
;

INSERT INTO norms(
    
    relation_name,
    join_var_name,
    aggregator_name,
    pred_col_name,
    fk_join_var_name,
    pk_relation_name,
    pk_join_var_name,
    
  pred_value_id,
  l0, l1, l2, l3, l_inf
)
SELECT
    
    'AKA_NAME' AS relation_name,
    'PERSON_ID' AS join_var_name,
    'MCV' AS aggregator_name,
    'NAME' AS pred_col_name,
    NULL AS fk_join_var_name,
    NULL AS pk_relation_name,
    NULL AS pk_join_var_name,
    
    mcv_id AS pred_value,
    COUNT(*) AS l0,
    SUM(POWER(deg, 1)) AS l1,
    SUM(POWER(deg, 2)) AS l2,
    SUM(POWER(deg, 3)) AS l3,
    MAX(deg) AS l_inf
FROM Degree_AKA_NAME_NAME_PERSON_ID
GROUP BY mcv_id
;

DROP TABLE IF EXISTS Degree_AKA_NAME_NAME_PERSON_ID;

-- Create aggregator table Degree_AKA_NAME_NAME_PERSON_ID for NONMCV AKA_NAME.NAME -- MCV
CREATE TEMP TABLE Degree_AKA_NAME_NAME_PERSON_ID AS
SELECT
    AKA_NAME.NAME AS NAME,
    AKA_NAME.PERSON_ID AS PERSON_ID,
    COUNT(*) AS deg
FROM AKA_NAME
LEFT JOIN AKA_NAME_NAME_mcv mcvt ON AKA_NAME.NAME = mcvt.NAME
WHERE AKA_NAME.PERSON_ID IS NOT NULL AND mcvt.mcv_id IS NULL 
GROUP BY
    AKA_NAME.NAME, AKA_NAME.PERSON_ID
;

-- Insert into norms for Non-MCV AKA_NAME NAME PERSON_ID NONMCV
-- Among all non-MCV values in Degree_AKA_NAME_NAME_PERSON_ID, find max of each Lp
WITH perValue AS (
  SELECT
    NAME,
    COUNT(*) AS l0, SUM(POWER(deg, 1)) AS l1, SUM(POWER(deg, 2)) AS l2, SUM(POWER(deg, 3)) AS l3, MAX(deg) AS l_inf
  FROM Degree_AKA_NAME_NAME_PERSON_ID
  GROUP BY NAME
  HAVING NAME IS NOT NULL
)
