pred_value_id,
l0, l1, l2, l3, l_inf
)
SELECT
    
    'AKA_TITLE' AS relation_name,
    'ID' AS join_var_name,
    'RANGE' AS aggregator_name,
    'PRODUCTION_YEAR' AS pred_col_name,
    'MOVIE_ID' AS fk_join_var_name,
    'TITLE' AS pk_relation_name,
    'ID' AS pk_join_var_name,
    
    bucket_id     AS pred_value,
    COUNT(*) AS l0,
    SUM(POWER(deg, 1)) AS l1,
    SUM(POWER(deg, 2)) AS l2,
    SUM(POWER(deg, 3)) AS l3,
    MAX(deg) AS l_inf
FROM 
(
  SELECT
        ID, bucket_id, SUM(deg) as deg
        FROM Degree_AKA_TITLE_MOVIE_ID_ID_TITLE_PRODUCTION_YEAR_ID d
        JOIN TITLE_PRODUCTION_YEAR_histogram h
        ON (h.lower_bound IS NULL OR d.PRODUCTION_YEAR >= h.lower_bound)
        AND (h.upper_bound IS NULL OR d.PRODUCTION_YEAR <= h.upper_bound)
    WHERE ID IS NOT NULL AND bucket_id IS NOT NULL
    GROUP BY ID, bucket_id
)
GROUP BY bucket_id
ORDER BY bucket_id
;

DROP TABLE IF EXISTS Degree_AKA_TITLE_MOVIE_ID;

-- Create aggregator table Degree_AKA_TITLE_MOVIE_ID
CREATE TEMP TABLE Degree_AKA_TITLE_MOVIE_ID AS
SELECT
    AKA_TITLE.MOVIE_ID AS MOVIE_ID,
    COUNT(*) AS deg
FROM AKA_TITLE

WHERE AKA_TITLE.MOVIE_ID IS NOT NULL
GROUP BY
    AKA_TITLE.MOVIE_ID
HAVING COUNT(*) > 0
ORDER BY deg DESC
;

