CREATE TEMP TABLE Degree_CAST_INFO_NOTE_ID AS
SELECT
    mcvt.mcv_id AS mcv_id,
    CAST_INFO.ID AS ID,
    COUNT(*) AS deg
FROM CAST_INFO
JOIN CAST_INFO_NOTE_mcv mcvt ON CAST_INFO.NOTE = mcvt.NOTE
WHERE CAST_INFO.ID IS NOT NULL
GROUP BY
    mcvt.mcv_id, CAST_INFO.ID
;

