  pred_value_id,
  l0, l1, l2, l3, l_inf
)
SELECT
    
    'CAST_INFO' AS relation_name,
    'MOVIE_ID' AS join_var_name,
    'NONMCV' AS aggregator_name,
    'NAME' AS pred_col_name,
    'PERSON_ID' AS fk_join_var_name,
    'NAME' AS pk_relation_name,
    'ID' AS pk_join_var_name,
    
  NULL              AS pred_value_id,
  MAX(l0) AS l0, MAX(l1) AS l1, MAX(l2) AS l2, MAX(l3) AS l3, MAX(l_inf) AS l_inf
FROM perValue
HAVING COUNT(*) > 0  -- If you need to ensure some rows are returned
;

