DROP TABLE IF EXISTS MOVIE_COMPANIES_MOVIE_ID_ID_TITLE;

-- Create temp table MOVIE_COMPANIES_MOVIE_ID_ID_TITLE (FK->PK join)
CREATE TEMP TABLE MOVIE_COMPANIES_MOVIE_ID_ID_TITLE AS
SELECT
    MOVIE_COMPANIES.ID AS ID, MOVIE_COMPANIES.MOVIE_ID AS MOVIE_ID, MOVIE_COMPANIES.COMPANY_ID AS COMPANY_ID, MOVIE_COMPANIES.COMPANY_TYPE_ID AS COMPANY_TYPE_ID,
    TITLE.PRODUCTION_YEAR AS TITLE_PRODUCTION_YEAR, TITLE.EPISODE_NR AS TITLE_EPISODE_NR, TITLE.TITLE AS TITLE_TITLE
FROM MOVIE_COMPANIES
JOIN TITLE
  ON MOVIE_COMPANIES.MOVIE_ID = TITLE.ID
;

DROP TABLE IF EXISTS MOVIE_COMPANIES_COMPANY_ID_ID_COMPANY_NAME;

-- Create temp table MOVIE_COMPANIES_COMPANY_ID_ID_COMPANY_NAME (FK->PK join)
CREATE TEMP TABLE MOVIE_COMPANIES_COMPANY_ID_ID_COMPANY_NAME AS
SELECT
    MOVIE_COMPANIES.ID AS ID, MOVIE_COMPANIES.MOVIE_ID AS MOVIE_ID, MOVIE_COMPANIES.COMPANY_ID AS COMPANY_ID, MOVIE_COMPANIES.COMPANY_TYPE_ID AS COMPANY_TYPE_ID,
    COMPANY_NAME.COUNTRY_CODE AS COMPANY_NAME_COUNTRY_CODE, COMPANY_NAME.NAME AS COMPANY_NAME_NAME
FROM MOVIE_COMPANIES
JOIN COMPANY_NAME
  ON MOVIE_COMPANIES.COMPANY_ID = COMPANY_NAME.ID
;

