    COMPANY_TYPE.KIND AS COMPANY_TYPE_KIND
FROM MOVIE_COMPANIES
JOIN COMPANY_TYPE
  ON MOVIE_COMPANIES.COMPANY_TYPE_ID = COMPANY_TYPE.ID
