DROP TABLE IF EXISTS Degree_MOVIE_COMPANIES_NOTE_MOVIE_ID;

-- Create aggregator table Degree_MOVIE_COMPANIES_NOTE_MOVIE_ID for MCV MOVIE_COMPANIES.NOTE -- MCV
CREATE TEMP TABLE Degree_MOVIE_COMPANIES_NOTE_MOVIE_ID AS
SELECT
    mcvt.mcv_id AS mcv_id,
    MOVIE_COMPANIES.MOVIE_ID AS MOVIE_ID,
    COUNT(*) AS deg
FROM MOVIE_COMPANIES
JOIN MOVIE_COMPANIES_NOTE_mcv mcvt ON MOVIE_COMPANIES.NOTE = mcvt.NOTE
WHERE MOVIE_COMPANIES.MOVIE_ID IS NOT NULL
GROUP BY
    mcvt.mcv_id, MOVIE_COMPANIES.MOVIE_ID
;

