    MOVIE_COMPANIES_COMPANY_ID_ID_COMPANY_NAME.COMPANY_TYPE_ID AS COMPANY_TYPE_ID,
    COUNT(*) AS deg
FROM MOVIE_COMPANIES_COMPANY_ID_ID_COMPANY_NAME
LEFT JOIN COMPANY_NAME_NAME_mcv mcvt ON MOVIE_COMPANIES_COMPANY_ID_ID_COMPANY_NAME.COMPANY_NAME_NAME = mcvt.NAME
WHERE MOVIE_COMPANIES_COMPANY_ID_ID_COMPANY_NAME.COMPANY_TYPE_ID IS NOT NULL AND mcvt.mcv_id IS NULL 
GROUP BY
    MOVIE_COMPANIES_COMPANY_ID_ID_COMPANY_NAME.COMPANY_NAME_NAME, MOVIE_COMPANIES_COMPANY_ID_ID_COMPANY_NAME.COMPANY_TYPE_ID
;

-- Insert into norms for Non-MCV MOVIE_COMPANIES_COMPANY_ID_ID_COMPANY_NAME NAME COMPANY_TYPE_ID NONMCV
-- Among all non-MCV values in Degree_MOVIE_COMPANIES_COMPANY_ID_ID_COMPANY_NAME_NAME_COMPANY_TYPE_ID, find max of each Lp
WITH perValue AS (
  SELECT
    NAME,
    COUNT(*) AS l0, SUM(POWER(deg, 1)) AS l1, SUM(POWER(deg, 2)) AS l2, SUM(POWER(deg, 3)) AS l3, MAX(deg) AS l_inf
  FROM Degree_MOVIE_COMPANIES_COMPANY_ID_ID_COMPANY_NAME_NAME_COMPANY_TYPE_ID
  GROUP BY NAME
  HAVING NAME IS NOT NULL
)
INSERT INTO norms(
    
    relation_name,
    join_var_name,
    aggregator_name,
    pred_col_name,
    fk_join_var_name,
    pk_relation_name,
    pk_join_var_name,
    
  pred_value_id,
  l0, l1, l2, l3, l_inf
)
SELECT
    
    'MOVIE_COMPANIES' AS relation_name,
    'COMPANY_TYPE_ID' AS join_var_name,
    'NONMCV' AS aggregator_name,
    'NAME' AS pred_col_name,
    'COMPANY_ID' AS fk_join_var_name,
    'COMPANY_NAME' AS pk_relation_name,
    'ID' AS pk_join_var_name,
    
  NULL              AS pred_value_id,
  MAX(l0) AS l0, MAX(l1) AS l1, MAX(l2) AS l2, MAX(l3) AS l3, MAX(l_inf) AS l_inf
FROM perValue
HAVING COUNT(*) > 0  -- If you need to ensure some rows are returned
;

