CREATE TEMP TABLE Degree_MOVIE_INFO_INFO_TYPE_ID_ID_INFO_TYPE_INFO_ID AS
SELECT
    MOVIE_INFO_INFO_TYPE_ID_ID_INFO_TYPE.INFO_TYPE_INFO AS INFO,
    MOVIE_INFO_INFO_TYPE_ID_ID_INFO_TYPE.ID AS ID,
    COUNT(*) AS deg
FROM MOVIE_INFO_INFO_TYPE_ID_ID_INFO_TYPE
