DROP TABLE IF EXISTS Degree_MOVIE_INFO_INFO_MOVIE_ID;

-- Create aggregator table Degree_MOVIE_INFO_INFO_MOVIE_ID for MCV MOVIE_INFO.INFO -- MCV
CREATE TEMP TABLE Degree_MOVIE_INFO_INFO_MOVIE_ID AS
SELECT
    mcvt.mcv_id AS mcv_id,
    MOVIE_INFO.MOVIE_ID AS MOVIE_ID,
    COUNT(*) AS deg
FROM MOVIE_INFO
JOIN MOVIE_INFO_INFO_mcv mcvt ON MOVIE_INFO.INFO = mcvt.INFO
WHERE MOVIE_INFO.MOVIE_ID IS NOT NULL
GROUP BY
    mcvt.mcv_id, MOVIE_INFO.MOVIE_ID
;

