  FROM Degree_MOVIE_INFO_IDX_MOVIE_ID_ID_TITLE_PRODUCTION_YEAR_MOVIE_ID
  GROUP BY PRODUCTION_YEAR
  HAVING PRODUCTION_YEAR IS NOT NULL
)
