    MOVIE_INFO_IDX_MOVIE_ID_ID_TITLE.MOVIE_ID AS MOVIE_ID,
    COUNT(*) AS deg
FROM MOVIE_INFO_IDX_MOVIE_ID_ID_TITLE

WHERE MOVIE_INFO_IDX_MOVIE_ID_ID_TITLE.MOVIE_ID IS NOT NULL
GROUP BY
