DROP TABLE IF EXISTS Degree_MOVIE_KEYWORD_MOVIE_ID_ID_TITLE_EPISODE_NR_KEYWORD_ID;

-- Create aggregator table Degree_MOVIE_KEYWORD_MOVIE_ID_ID_TITLE_EPISODE_NR_KEYWORD_ID for Histogram MOVIE_KEYWORD_MOVIE_ID_ID_TITLE.TITLE_EPISODE_NR -- FKPK_RANGE
CREATE TEMP TABLE Degree_MOVIE_KEYWORD_MOVIE_ID_ID_TITLE_EPISODE_NR_KEYWORD_ID AS
SELECT
    MOVIE_KEYWORD_MOVIE_ID_ID_TITLE.TITLE_EPISODE_NR AS EPISODE_NR,
    MOVIE_KEYWORD_MOVIE_ID_ID_TITLE.KEYWORD_ID AS KEYWORD_ID,
    COUNT(*) AS deg
FROM MOVIE_KEYWORD_MOVIE_ID_ID_TITLE

WHERE MOVIE_KEYWORD_MOVIE_ID_ID_TITLE.KEYWORD_ID IS NOT NULL
GROUP BY
    MOVIE_KEYWORD_MOVIE_ID_ID_TITLE.TITLE_EPISODE_NR, MOVIE_KEYWORD_MOVIE_ID_ID_TITLE.KEYWORD_ID
