INSERT INTO norms(

    relation_name,
    join_var_name,
    aggregator_name,
    pred_col_name,
    fk_join_var_name,
    pk_relation_name,
    pk_join_var_name,
    
pred_value_id,
l0, l1, l2, l3, l_inf
)
SELECT
    
    'MOVIE_KEYWORD' AS relation_name,
    'KEYWORD_ID' AS join_var_name,
    'RANGE' AS aggregator_name,
    'EPISODE_NR' AS pred_col_name,
    'MOVIE_ID' AS fk_join_var_name,
    'TITLE' AS pk_relation_name,
    'ID' AS pk_join_var_name,
    
    bucket_id     AS pred_value,
    COUNT(*) AS l0,
    SUM(POWER(deg, 1)) AS l1,
    SUM(POWER(deg, 2)) AS l2,
    SUM(POWER(deg, 3)) AS l3,
    MAX(deg) AS l_inf
FROM 
(
  SELECT
        KEYWORD_ID, bucket_id, SUM(deg) as deg
        FROM Degree_MOVIE_KEYWORD_MOVIE_ID_ID_TITLE_EPISODE_NR_KEYWORD_ID d
        JOIN TITLE_EPISODE_NR_histogram h
        ON (h.lower_bound IS NULL OR d.EPISODE_NR >= h.lower_bound)
        AND (h.upper_bound IS NULL OR d.EPISODE_NR <= h.upper_bound)
    WHERE KEYWORD_ID IS NOT NULL AND bucket_id IS NOT NULL
    GROUP BY KEYWORD_ID, bucket_id
)
GROUP BY bucket_id
ORDER BY bucket_id
;

