        ON (h.lower_bound IS NULL OR d.PRODUCTION_YEAR >= h.lower_bound)
        AND (h.upper_bound IS NULL OR d.PRODUCTION_YEAR <= h.upper_bound)
    WHERE MOVIE_ID IS NOT NULL AND bucket_id IS NOT NULL
    GROUP BY MOVIE_ID, bucket_id
)
GROUP BY bucket_id
ORDER BY bucket_id
;

DROP TABLE IF EXISTS Degree_MOVIE_LINK_LINK_TYPE_ID_ID_LINK_TYPE_LINK_MOVIE_ID;

-- Create aggregator table Degree_MOVIE_LINK_LINK_TYPE_ID_ID_LINK_TYPE_LINK_MOVIE_ID for MCV MOVIE_LINK_LINK_TYPE_ID_ID_LINK_TYPE.LINK_TYPE_LINK -- FKPK_MCV
CREATE TEMP TABLE Degree_MOVIE_LINK_LINK_TYPE_ID_ID_LINK_TYPE_LINK_MOVIE_ID AS
SELECT
    mcvt.mcv_id AS mcv_id,
    MOVIE_LINK_LINK_TYPE_ID_ID_LINK_TYPE.MOVIE_ID AS MOVIE_ID,
    COUNT(*) AS deg
FROM MOVIE_LINK_LINK_TYPE_ID_ID_LINK_TYPE
JOIN LINK_TYPE_LINK_mcv mcvt ON MOVIE_LINK_LINK_TYPE_ID_ID_LINK_TYPE.LINK_TYPE_LINK = mcvt.LINK
WHERE MOVIE_LINK_LINK_TYPE_ID_ID_LINK_TYPE.MOVIE_ID IS NOT NULL
GROUP BY
    mcvt.mcv_id, MOVIE_LINK_LINK_TYPE_ID_ID_LINK_TYPE.MOVIE_ID
;

