DROP TABLE IF EXISTS PERSON_INFO_PERSON_ID_ID_NAME;

-- Create temp table PERSON_INFO_PERSON_ID_ID_NAME (FK->PK join)
CREATE TEMP TABLE PERSON_INFO_PERSON_ID_ID_NAME AS
SELECT
    PERSON_INFO.ID AS ID, PERSON_INFO.PERSON_ID AS PERSON_ID, PERSON_INFO.INFO_TYPE_ID AS INFO_TYPE_ID,
    NAME.GENDER AS NAME_GENDER, NAME.NAME_PCODE_CF AS NAME_NAME_PCODE_CF, NAME.NAME AS NAME_NAME
FROM PERSON_INFO
JOIN NAME
  ON PERSON_INFO.PERSON_ID = NAME.ID
;

DROP TABLE IF EXISTS PERSON_INFO_INFO_TYPE_ID_ID_INFO_TYPE;

-- Create temp table PERSON_INFO_INFO_TYPE_ID_ID_INFO_TYPE (FK->PK join)
CREATE TEMP TABLE PERSON_INFO_INFO_TYPE_ID_ID_INFO_TYPE AS
SELECT
    PERSON_INFO.ID AS ID, PERSON_INFO.PERSON_ID AS PERSON_ID, PERSON_INFO.INFO_TYPE_ID AS INFO_TYPE_ID,
    INFO_TYPE.INFO AS INFO_TYPE_INFO
FROM PERSON_INFO
JOIN INFO_TYPE
  ON PERSON_INFO.INFO_TYPE_ID = INFO_TYPE.ID
;

