-- Create aggregator table Degree_PERSON_INFO_INFO_TYPE_ID_ID_INFO_TYPE_INFO_PERSON_ID for MCV PERSON_INFO_INFO_TYPE_ID_ID_INFO_TYPE.INFO_TYPE_INFO -- FKPK_MCV
