    'NONMCV' AS aggregator_name,
    'PRODUCTION_YEAR' AS pred_col_name,
    NULL AS fk_join_var_name,
    NULL AS pk_relation_name,
    NULL AS pk_join_var_name,
    
  NULL              AS pred_value_id,
  MAX(l0) AS l0, MAX(l1) AS l1, MAX(l2) AS l2, MAX(l3) AS l3, MAX(l_inf) AS l_inf
FROM perValue
HAVING COUNT(*) > 0  -- If you need to ensure some rows are returned
;

DROP TABLE IF EXISTS Degree_TITLE_TITLE_KIND_ID;

-- Create aggregator table Degree_TITLE_TITLE_KIND_ID for MCV TITLE.TITLE -- MCV
CREATE TEMP TABLE Degree_TITLE_TITLE_KIND_ID AS
SELECT
    mcvt.mcv_id AS mcv_id,
    TITLE.KIND_ID AS KIND_ID,
    COUNT(*) AS deg
FROM TITLE
JOIN TITLE_TITLE_mcv mcvt ON TITLE.TITLE = mcvt.TITLE
WHERE TITLE.KIND_ID IS NOT NULL
GROUP BY
    mcvt.mcv_id, TITLE.KIND_ID
;

INSERT INTO norms(
    
    relation_name,
    join_var_name,
    aggregator_name,
    pred_col_name,
    fk_join_var_name,
    pk_relation_name,
    pk_join_var_name,
    
  pred_value_id,
  l0, l1, l2, l3, l_inf
)
SELECT
    
    'TITLE' AS relation_name,
    'KIND_ID' AS join_var_name,
    'MCV' AS aggregator_name,
    'TITLE' AS pred_col_name,
    NULL AS fk_join_var_name,
    NULL AS pk_relation_name,
    NULL AS pk_join_var_name,
    
    mcv_id AS pred_value,
    COUNT(*) AS l0,
    SUM(POWER(deg, 1)) AS l1,
    SUM(POWER(deg, 2)) AS l2,
    SUM(POWER(deg, 3)) AS l3,
    MAX(deg) AS l_inf
FROM Degree_TITLE_TITLE_KIND_ID
GROUP BY mcv_id
;

DROP TABLE IF EXISTS Degree_TITLE_TITLE_KIND_ID;

-- Create aggregator table Degree_TITLE_TITLE_KIND_ID for NONMCV TITLE.TITLE -- MCV
CREATE TEMP TABLE Degree_TITLE_TITLE_KIND_ID AS
SELECT
    TITLE.TITLE AS TITLE,
    TITLE.KIND_ID AS KIND_ID,
    COUNT(*) AS deg
FROM TITLE
LEFT JOIN TITLE_TITLE_mcv mcvt ON TITLE.TITLE = mcvt.TITLE
WHERE TITLE.KIND_ID IS NOT NULL AND mcvt.mcv_id IS NULL 
GROUP BY
    TITLE.TITLE, TITLE.KIND_ID
;

-- Insert into norms for Non-MCV TITLE TITLE KIND_ID NONMCV
-- Among all non-MCV values in Degree_TITLE_TITLE_KIND_ID, find max of each Lp
WITH perValue AS (
  SELECT
    TITLE,
    COUNT(*) AS l0, SUM(POWER(deg, 1)) AS l1, SUM(POWER(deg, 2)) AS l2, SUM(POWER(deg, 3)) AS l3, MAX(deg) AS l_inf
  FROM Degree_TITLE_TITLE_KIND_ID
  GROUP BY TITLE
  HAVING TITLE IS NOT NULL
)
INSERT INTO norms(
    
    relation_name,
    join_var_name,
    aggregator_name,
    pred_col_name,
    fk_join_var_name,
    pk_relation_name,
    pk_join_var_name,
    
  pred_value_id,
  l0, l1, l2, l3, l_inf
)
SELECT
    
    'TITLE' AS relation_name,
    'KIND_ID' AS join_var_name,
    'NONMCV' AS aggregator_name,
    'TITLE' AS pred_col_name,
    NULL AS fk_join_var_name,
    NULL AS pk_relation_name,
    NULL AS pk_join_var_name,
    
  NULL              AS pred_value_id,
  MAX(l0) AS l0, MAX(l1) AS l1, MAX(l2) AS l2, MAX(l3) AS l3, MAX(l_inf) AS l_inf
FROM perValue
HAVING COUNT(*) > 0  -- If you need to ensure some rows are returned
;

DROP TABLE IF EXISTS Degree_TITLE_EPISODE_NR_KIND_ID;

-- Create aggregator table Degree_TITLE_EPISODE_NR_KIND_ID for Histogram TITLE.EPISODE_NR -- RANGE
CREATE TEMP TABLE Degree_TITLE_EPISODE_NR_KIND_ID AS
SELECT
    TITLE.EPISODE_NR AS EPISODE_NR,
    TITLE.KIND_ID AS KIND_ID,
    COUNT(*) AS deg
FROM TITLE

WHERE TITLE.KIND_ID IS NOT NULL
GROUP BY
    TITLE.EPISODE_NR, TITLE.KIND_ID
;

INSERT INTO norms(

    relation_name,
    join_var_name,
    aggregator_name,
    pred_col_name,
    fk_join_var_name,
    pk_relation_name,
    pk_join_var_name,
    
pred_value_id,
l0, l1, l2, l3, l_inf
)
SELECT
    
    'TITLE' AS relation_name,
    'KIND_ID' AS join_var_name,
    'RANGE' AS aggregator_name,
    'EPISODE_NR' AS pred_col_name,
    NULL AS fk_join_var_name,
    NULL AS pk_relation_name,
    NULL AS pk_join_var_name,
    
    bucket_id     AS pred_value,
    COUNT(*) AS l0,
    SUM(POWER(deg, 1)) AS l1,
    SUM(POWER(deg, 2)) AS l2,
    SUM(POWER(deg, 3)) AS l3,
    MAX(deg) AS l_inf
FROM 
(
  SELECT
        KIND_ID, bucket_id, SUM(deg) as deg
        FROM Degree_TITLE_EPISODE_NR_KIND_ID d
        JOIN TITLE_EPISODE_NR_histogram h
        ON (h.lower_bound IS NULL OR d.EPISODE_NR >= h.lower_bound)
        AND (h.upper_bound IS NULL OR d.EPISODE_NR <= h.upper_bound)
    WHERE KIND_ID IS NOT NULL AND bucket_id IS NOT NULL
    GROUP BY KIND_ID, bucket_id
)
GROUP BY bucket_id
ORDER BY bucket_id
;

